SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `clients`;

CREATE TABLE `clients`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`id_number` INTEGER NOT NULL,
`email` TEXT   NULL DEFAULT NULL,
`telephone` TEXT   NOT NULL,
`address` TEXT   NULL DEFAULT NULL,
`comment` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `config`;

CREATE TABLE `config`  (
`id` INTEGER  NOT NULL ,
`key` TEXT   NOT NULL,
`value` text   NOT NULL,
`description` text   NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `deposits`;

CREATE TABLE `deposits`  (
`id` INTEGER  NOT NULL ,
`client_id` INTEGER  NOT NULL,
`sale_id` INTEGER NULL DEFAULT NULL,
`amount` double(15, 2) NOT NULL,
`comment` text   NULL,
`claimed` tinyINTEGER NULL DEFAULT NULL,
`claimed_in_sale_id` INTEGER NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
);
DROP TABLE IF EXISTS `expenses`;

CREATE TABLE `expenses`  (
`id` INTEGER  NOT NULL ,
`description` text   NOT NULL,
`amount` double(15, 2) NOT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
);
DROP TABLE IF EXISTS `loan_payments`;

CREATE TABLE `loan_payments`  (
`id` INTEGER  NOT NULL ,
`loan_id` INTEGER  NOT NULL,
`amount` double NOT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
`payment_method_id` INTEGER NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`loan_id`) REFERENCES `loans` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `loans`;

CREATE TABLE `loans`  (
`id` INTEGER  NOT NULL ,
`client_id` INTEGER  NOT NULL,
`sale_id` INTEGER NULL DEFAULT NULL,
`amount` double(15, 2) NOT NULL,
`comment` text   NULL,
`created_by` INTEGER  NOT NULL,
`closed` tinyINTEGER NULL DEFAULT 0,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
);
DROP TABLE IF EXISTS `migrations`;

CREATE TABLE `migrations`  (
`id` INTEGER  NOT NULL ,
`migration` TEXT   NOT NULL,
`batch` INTEGER NOT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `password_resets`;

CREATE TABLE `password_resets`  (
`email` TEXT   NOT NULL,
`token` TEXT   NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
);
DROP TABLE IF EXISTS `payment_methods`;

CREATE TABLE `payment_methods`  (
`id` INTEGER  NOT NULL ,
`identifier` TEXT   NOT NULL,
`name` TEXT   NOT NULL,
`description` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `payment_status`;

CREATE TABLE `payment_status`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `payments`;

CREATE TABLE `payments`  (
`id` INTEGER  NOT NULL ,
`sale_id` INTEGER  NOT NULL,
`client_id` INTEGER  NOT NULL,
`payment_method_id` INTEGER  NOT NULL,
`amount` double(15, 2) NOT NULL,
`amount_bs` double(15, 2) NULL DEFAULT NULL,
`comment` text   NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
FOREIGN KEY (`payment_method_id`) REFERENCES `payment_methods` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (`sale_id`) REFERENCES `sales` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `product_categories`;

CREATE TABLE `product_categories`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`slug` TEXT   NOT NULL,
`description` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
UNIQUE INDEX `product_categories_name_unique`(`name`),
UNIQUE INDEX `product_categories_slug_unique`(`slug`)
);
DROP TABLE IF EXISTS `products`;

CREATE TABLE `products`  (
`id` INTEGER  NOT NULL ,
`identifier` TEXT   NOT NULL,
`name` TEXT   NOT NULL,
`product_category_id` INTEGER  NOT NULL,
`description` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`product_category_id`) REFERENCES `product_categories` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `roles`;

CREATE TABLE `roles`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`p_sales` tinyINTEGER  NULL DEFAULT NULL,
`p_sell` tinyINTEGER NULL DEFAULT NULL,
`p_s_inventory` tinyINTEGER NULL DEFAULT NULL,
`p_e_inventory` tinyINTEGER NULL DEFAULT NULL,
`p_s_clients` tinyINTEGER NULL DEFAULT NULL,
`p_e_clients` tinyINTEGER NULL DEFAULT NULL,
`p_s_credits` tinyINTEGER NULL DEFAULT NULL,
`p_e_credits` tinyINTEGER NULL DEFAULT NULL,
`p_discount` tinyINTEGER NULL DEFAULT NULL,
`p_reports` tinyINTEGER NULL DEFAULT NULL,
`p_users` tinyINTEGER NULL DEFAULT NULL,
`p_config` tinyINTEGER NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
UNIQUE INDEX `roles_name_unique`(`name`)
);
DROP TABLE IF EXISTS `sale_details`;

CREATE TABLE `sale_details`  (
`id` INTEGER  NOT NULL ,
`sale_id` INTEGER  NOT NULL,
`product_id` INTEGER  NOT NULL,
`stock_id` INTEGER  NOT NULL,
`price` double(15, 2) NOT NULL,
`cost_price` double(15, 2) NOT NULL,
`qty` INTEGER NOT NULL,
`returned` INTEGER NULL DEFAULT 0,
`returned_reason` INTEGER NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`authorized_by` INTEGER  NULL DEFAULT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
`gift` INTEGER NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (`sale_id`) REFERENCES `sales` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `sale_status`;

CREATE TABLE `sale_status`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `sales`;

CREATE TABLE `sales`  (
`id` INTEGER  NOT NULL ,
`client_id` INTEGER  NOT NULL,
`amount` double(15, 2) NULL DEFAULT 0.00,
`comment` text   NULL,
`sale_status_id` INTEGER  NOT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
`closed_at` datetime(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
FOREIGN KEY (`sale_status_id`) REFERENCES `sale_status` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
);
DROP TABLE IF EXISTS `stock`;

CREATE TABLE `stock`  (
`id` INTEGER  NOT NULL ,
`product_id` INTEGER  NOT NULL,
`warehouse_id` INTEGER  NOT NULL,
`qty` INTEGER NOT NULL,
`price` double(15, 2) NOT NULL,
`cost_price` double(15, 2) NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
FOREIGN KEY (`warehouse_id`) REFERENCES `warehouses` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `stock_log`;

CREATE TABLE `stock_log`  (
`id` INTEGER  NOT NULL ,
`product_id` INTEGER  NOT NULL,
`message` TEXT   NOT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`)
);
DROP TABLE IF EXISTS `users`;

CREATE TABLE `users`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`email` TEXT   NOT NULL,
`rol_id` INTEGER  NULL DEFAULT NULL,
`is_active` tinyINTEGER NOT NULL DEFAULT 1,
`email_verified_at` timestamp(0) NULL DEFAULT NULL,
`password` TEXT   NOT NULL,
`remember_token` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
FOREIGN KEY (`rol_id`) REFERENCES `roles` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
);
DROP TABLE IF EXISTS `warehouses`;

CREATE TABLE `warehouses`  (
`id` INTEGER  NOT NULL ,
`name` TEXT   NOT NULL,
`slug` TEXT   NOT NULL,
`is_default` tinyINTEGER NULL DEFAULT NULL,
`description` TEXT   NULL DEFAULT NULL,
`created_by` INTEGER  NOT NULL,
`created_at` timestamp(0) NULL DEFAULT NULL,
`updated_at` timestamp(0) NULL DEFAULT NULL,
PRIMARY KEY (`id`),
UNIQUE INDEX `warehouses_slug_unique`(`slug`)
);
